java
public String repeatEnd(String str, int n) {
    if (n > str.length()) {
        // n can't be greater than string length
        n = str.length();
    }
    StringBuilder sb = new StringBuilder();
    for (int i = 0; i < n; i++) {
        sb.append(str.substring(Math.max(str.length() - n, 0)));
    }
    return sb.toString();
}

